#include <stdio.h>

int main() {
    int num1;
    int num2;

    // Read two integers from stdin
    scanf("%d %d", &num1, &num2);

    // Calculate their sum and print it
    printf("%d\n", num1 + num2);

    return 0;
}

#include <stdio.h>

int main() {
    int a;
    int b;

    // Read two integers
    scanf("%d %d", &a, &b);

    // Calculate and print product
    printf("%d\n", a * b);

    // Calculate and print integer quotient
    printf("%d\n", a / b);

    return 0;
}

#include <stdio.h>

int main() {
    int dividend;
    int divisor;

    // Read two positive integers
    scanf("%d %d", &dividend, &divisor);

    // Calculate and print the remainder
    printf("%d\n", dividend % divisor);

    return 0;
}

#include <stdio.h>

int main() {
    int length;
    int width;

    // Read length and width
    scanf("%d %d", &length, &width);

    // Calculate and print the area
    printf("%d\n", length * width);

    return 0;
}

#include <stdio.h>

int main() {
    int num1, num2, num3;

    // Read three integers
    scanf("%d %d %d", &num1, &num2, &num3);

    // Calculate sum as float to ensure float division
    float sum = (float)(num1 + num2 + num3);
    float average = sum / 3.0f; // Use 3.0f to ensure float division

    // Print the average rounded to two decimal places
    printf("%.2f\n", average);

    return 0;
}

#include <stdio.h>

int main() {
    float celsius;

    // Read Celsius temperature
    scanf("%f", &celsius);

    // Convert to Fahrenheit using the formula
    // Use 9.0f/5.0f to ensure float division
    float fahrenheit = celsius * (9.0f / 5.0f) + 32.0f;

    // Print Fahrenheit temperature rounded to one decimal place
    printf("%.1f\n", fahrenheit);

    return 0;
}

#include <stdio.h>

int main() {
    int num1;
    int num2;
    int temp; // Temporary variable for swapping

    // Read the two integers
    scanf("%d %d", &num1, &num2);

    // Swap the values using a temporary variable
    temp = num1;
    num1 = num2;
    num2 = temp;

    // Print the swapped values
    printf("%d %d\n", num1, num2);

    return 0;
}

#include <stdio.h>

int main() {
    int value;
    int original_value;

    // Read the integer
    scanf("%d", &value);

    // Store the original value for the decrement operation
    original_value = value;

    // Increment value and print
    value++;
    printf("%d\n", value);

    // Decrement original_value and print
    original_value--;
    printf("%d\n", original_value);

    return 0;
}

#include <stdio.h>

int main() {
    int num;

    // Read the integer
    scanf("%d", &num);

    // Check if the number is even (remainder when divided by 2 is 0)
    // The expression (num % 2 == 0) evaluates to 1 (true) or 0 (false)
    printf("%d\n", (num % 2 == 0));

    return 0;
}

#include <stdio.h>

int main() {
    int condition1;
    int condition2;

    // Read two integers representing boolean values
    scanf("%d %d", &condition1, &condition2);

    // Compute their logical AND
    // The expression (condition1 && condition2) evaluates to 1 (true) or 0 (false)
    printf("%d\n", (condition1 && condition2));

    return 0;
}
